import base64, os
chunk = base64.b64decode("").decode()
with open("/opt/polymarket-agent/autotrader.py", "a") as f:
    f.write(chunk)
print("autotrader chunk 3 written")

import base64, os
sc = base64.b64decode("").decode()
with open("/opt/polymarket-agent/opportunity_scanner.py", "w") as f:
    f.write(sc)
print(f"scanner written: {len(sc)} chars")

import subprocess, os, sys
# Clear pycache
result = subprocess.run(['find', '/opt/polymarket-agent/__pycache__',
    '-name', 'autotrader*.pyc', '-delete'], capture_output=True)
result2 = subprocess.run(['find', '/opt/polymarket-agent/__pycache__',
    '-name', 'opportunity_scanner*.pyc', '-delete'], capture_output=True)
print("pycache cleared")

# Restart service
result3 = subprocess.run(['systemctl', 'restart', 'polymarket'], capture_output=True)
print(f"service restart: rc={result3.returncode}")

# Verify
with open("/opt/polymarket-agent/autotrader.py") as f:
    at = f.read()
with open("/opt/polymarket-agent/opportunity_scanner.py") as f:
    sc = f.read()
print(f"autotrader size: {len(at):,}")
print(f"_track_usage: {'_track_usage' in at}")
print(f"_HAIKU_IN_PRICE: {'_HAIKU_IN_PRICE' in at}")
print(f"scanner size: {len(sc):,}")
print(f"_sc_track: {'_sc_track' in sc}")
